mapper.select:
SELECT dp.*, dz.id_device, dz.field_0L, dz.field_0R, d.BreakerPresentPanel0L, d.BreakerPresentPanel0R, d.BreakerPresentPanel1L, d.BreakerPresentPanel1R, d.BreakerPresentPanel2L, d.BreakerPresentPanel2R
FROM device_zone_map dp LEFT JOIN device_zone dz ON dz.id = dp.id_zone
LEFT JOIN ( SELECT * FROM ${datatablename} d ORDER BY d.time DESC LIMIT 1 ) d ON d.id_device = dz.id_device WHERE dp.id_zone = #{id_zone} GROUP BY dp.id;
